// Убираем приветствия и личные шаблоны без конкретной темы прямо из массива
(function() {
  var USEFUL = { medical:1, no_report:1, report_first:1, report_final:1, motivation:1, info:1 };
  var GREET  = ['здравствуйте','добрый','доброго','доброе','дравствуйте','приветствую','рада привет'];
  var GENERIC = { 'отчет':1, 'спасибо':1, 'ответ на отчет':1, 'здравствуйте':1, 'привет':1 };
  for (var i = TEMPLATES_LIBRARY.length - 1; i >= 0; i--) {
    var t  = TEMPLATES_LIBRARY[i];
    var nl = t.name.toLowerCase();
    if (t.category === 'greeting') { TEMPLATES_LIBRARY.splice(i, 1); continue; }
    if (GREET.some(function(p){ return nl.indexOf(p) !== -1; })) { TEMPLATES_LIBRARY.splice(i, 1); continue; }
    if (USEFUL[t.category]) continue;
    // general — оставляем только с конкретной темой
    var hasSpecific = t.keywords && t.keywords.some(function(kw){ return !GENERIC[kw.toLowerCase()]; });
    if (!hasSpecific) TEMPLATES_LIBRARY.splice(i, 1);
  }
})();

// Нормализация: ё→е, ударения, нижний регистр
function _norm(s) {
  return s.toLowerCase()
    .replace(/ё/g, 'е')
    .replace(/й/g, 'и');
}

// Стемминг: берём первые N символов (для русского языка достаточно 5-6)
function _stem(word) {
  return word.length > 5 ? word.slice(0, 5) : word;
}

// Совпадение ключевого слова с текстом: точное вхождение ИЛИ стемм-совпадение
// Длинные фразы дают больше очков (специфичность)
function _kwMatch(text, kw) {
  var wordCount = kw.split(/\s+/).filter(function(p) { return p.length > 1; }).length || 1;
  // Точное вхождение: очки пропорциональны количеству слов в фразе
  if (text.indexOf(kw) !== -1) return wordCount * 2;
  // Стемм-совпадение: каждое слово ключа ищем как стемм в тексте
  var parts = kw.split(/\s+/).filter(function(p) { return p.length > 2; });
  if (!parts.length) return 0;
  var matches = parts.filter(function(p) { return text.indexOf(_stem(p)) !== -1; });
  return matches.length === parts.length ? wordCount : 0;
}

// Поиск подходящих шаблонов по тексту сообщения ученика
function findMatchingTemplates(studentMessage, limit) {
  if (!studentMessage) return [];
  limit = limit || 3;
  var norm = _norm(studentMessage);
  var scores = [];

  for (var i = 0; i < TEMPLATES_LIBRARY.length; i++) {
    var tpl = TEMPLATES_LIBRARY[i];
    var score = 0;
    for (var j = 0; j < tpl.keywords.length; j++) {
      score += _kwMatch(norm, _norm(tpl.keywords[j]));
    }
    if (score > 0) scores.push({ tpl: tpl, score: score });
  }

  scores.sort(function(a, b) { return b.score - a.score; });
  return scores.slice(0, limit).map(function(s) { return s.tpl; });
}

// Поиск всех шаблонов по поисковому запросу (для дропдауна)
// Сортировка: совпадение по имени — выше, по тексту — ниже
function searchTemplates(query) {
  if (!query || !query.trim()) return TEMPLATES_LIBRARY;
  var q = _norm(query.trim());
  var results = [];
  for (var i = 0; i < TEMPLATES_LIBRARY.length; i++) {
    var tpl = TEMPLATES_LIBRARY[i];
    var normName = _norm(tpl.name);
    var normText = _norm(tpl.text);
    // Приоритет: 3 = точное совпадение имени, 2 = имя содержит запрос, 1 = текст содержит
    var priority = 0;
    if (normName === q) priority = 3;
    else if (normName.indexOf(q) !== -1) priority = 2;
    else if (normText.indexOf(q) !== -1) priority = 1;
    if (priority > 0) results.push({ tpl: tpl, priority: priority });
  }
  results.sort(function(a, b) { return b.priority - a.priority; });
  return results.map(function(r) { return r.tpl; });
}